# Initialize dictionaries for direct aggregation to avoid large intermediate DataFrames
yearly_filings_counts = defaultdict(lambda: defaultdict(int))
cpc_group_titles_counter = defaultdict(Counter) # Use Counter to directly count titles per CPC group

with open(file_path, 'r') as f:
    data = json.load(f)

for record in data:
    grant_date_str = record.get("grant_date")
    filing_date_str = record.get("filing_date")
